import React, { useState } from 'react';
import './Settings.css';
import StudentData from './StudentData'; // Fixed Import
import AdminUserPanel from './AdminUserPanel';

const AdminLogin = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [selectedOption, setSelectedOption] = useState(''); // Track selected panel

  const handleLogin = (e) => {
    e.preventDefault();
    
    // Replace with actual credentials
    if (username === ' ' && password === ' ') {
      setIsLoggedIn(true);
    } else {
      alert('Invalid credentials');
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUsername('');
    setPassword('');
    setSelectedOption(''); // Reset selected option
  };

  const handleOptionSelect = (option) => {
    setSelectedOption(option);
  };

  return (
    <div className="admin-layout">
      {!isLoggedIn ? (
        // Login Form
        <div className="admin-login-container">
          <h2>Admin Login</h2>
          <form onSubmit={handleLogin}>
            <div className="input-group">
              <label>Username:</label>
              <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} required />
            </div>
            <div className="input-group">
              <label>Password:</label>
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <div className="button-container">
              <button type="submit">Login</button>
            </div>
          </form>
        </div>
      ) : selectedOption === 'addStudent' ? (  
        // Show Student Data Panel
        <div className="student-data-container">
          <StudentData setView={setSelectedOption} />
          <button onClick={() => setSelectedOption('')} className="back-button">
            Back
          </button>
        </div>
      ) : selectedOption === 'adminUserModification' ? ( 
        
        <div className="student-data-container">
          <AdminUserPanel setView={setSelectedOption} />
          <button onClick={() => setSelectedOption('')} className="back-button">
            Back
          </button>
        </div>
      ) : (
        // Admin Panel
        <div className="admin-panel-wrapper">
            <h2 style={{ marginBottom: '30px', fontSize: '28px', fontWeight: 'bold', color: '#2c3e50' }}>
              Welcome, Admin 👋
            </h2>
            
            <div className="admin-panel">
              <h3>Admin Panel</h3>
              <p>Modify Admin Data and Password</p>
              <button className="settings-button" onClick={() => handleOptionSelect('adminUserModification')}>
                Manage Admins
              </button>
            </div>

            <div className="admin-panel">
              <h3>Student Timetable Panel</h3>
              <p>Modify Student Timetable and Allocated Rooms</p>
              <button className="settings-button" onClick={() => handleOptionSelect('addStudent')}>
                Manage Timetable
              </button>
            </div>

            <button onClick={handleLogout} className="back-button">Back to Login</button>
          </div>

      )}
    </div>
  );
};

export default AdminLogin;
